+        conn.execute("INSERT INTO ga VALUES ('b', 20);").unwrap();
+
+        let rows = conn
+            .query("SELECT t.* FROM ga AS t GROUP BY k, v ORDER BY k, v;")
+            .unwrap();
+        assert_eq!(rows.len(), 2);
+        assert_eq!(
+            row_values(&rows[0]),
+            vec![SqliteValue::Text("a".to_owned()), SqliteValue::Integer(10)]
+        );
